**VMA 分配**：

```c
static struct vma *alloc_vma(void) {
    acquire(&vmas_lock);
    for (int i = 0; i < NVMA; i++) {
        if (vmas[i].used == 0) {
            vmas[i].used = 1;
            release(&vmas_lock);
            return &vmas[i];
        }
    }
    release(&vmas_lock);
    return 0;
}
