            if (start != vma->startva) {
                if (split_vma(mm, vma, start, 1) < 0) return MAP_FAILED;
            }
            if (end != vma->startva + vma->size) {
                if (split_vma(mm, vma, end, 0) < 0) return MAP_FAILED;
            }
            del_vma_from_vmspace(&mm->head_vma, vma);
            mapva = addr;
        }
